import{_ as s,o as t,c as n,a0 as e}from"./chunks/framework.DV6pVIgV.js";const b=JSON.parse('{"title":"無伺服器運算：Lambda 與 Step Functions","description":"","frontmatter":{},"headers":[],"relativePath":"clf-c02/4.md","filePath":"clf-c02/4.md","lastUpdated":1783683951000}'),r={name:"clf-c02/4.md"};function o(l,a,p,i,d,h){return t(),n("div",null,[...a[0]||(a[0]=[e(`<h1 id="無伺服器運算-lambda-與-step-functions" tabindex="-1">無伺服器運算：Lambda 與 Step Functions <a class="header-anchor" href="#無伺服器運算-lambda-與-step-functions" aria-label="Permalink to &quot;無伺服器運算：Lambda 與 Step Functions&quot;">​</a></h1><p>上一章是 EC2（自己管一台虛擬機）；這章看「<strong>完全不用管伺服器的運算方式</strong>」——事件觸發的函式（Lambda）與多步驟流程編排（Step Functions）。</p><h2 id="先備知識" tabindex="-1">先備知識 <a class="header-anchor" href="#先備知識" aria-label="Permalink to &quot;先備知識&quot;">​</a></h2><ul><li><p><strong>無伺服器（Serverless）</strong></p><ul><li><a href="https://hackmd.io/@CynthiaChuang/Serverless-Use-Cases-Study-Notes-01" target="_blank" rel="noreferrer">【Serverless 應用案例賞析筆記】01. Serverless 架構與 Apache OpenWhisk</a></li><li><a href="https://ithelp.ithome.com.tw/m/articles/10235486" target="_blank" rel="noreferrer">Day 01 - 萬里之行，始於足下：認識Serverless</a></li></ul></li><li><p><strong>編排（Orchestration）</strong></p><ul><li><a href="https://www.educative.io/answers/what-is-serverless-orchestration" target="_blank" rel="noreferrer">Educative：What is serverless orchestration?</a></li><li><a href="https://ithelp.ithome.com.tw/articles/10381221" target="_blank" rel="noreferrer">iThome：Workflow Orchestration 流程編排介紹</a></li></ul></li></ul><h2 id="什麼是無伺服器-serverless" tabindex="-1">什麼是無伺服器（Serverless） <a class="header-anchor" href="#什麼是無伺服器-serverless" aria-label="Permalink to &quot;什麼是無伺服器（Serverless）&quot;">​</a></h2><p>「無伺服器」不是真的沒有伺服器，而是「<strong>你不用管伺服器</strong>」。底層的佈建、擴展、修補全部由 AWS 處理；你只負責程式碼，且<strong>只在程式實際執行時才付費，閒置不收費</strong>。</p><p>對比 EC2：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>EC2（有伺服器）                無伺服器（如 Lambda）</span></span>
<span class="line"><span>─────────────────              ─────────────────────</span></span>
<span class="line"><span>你租一台機器                   你上傳程式碼</span></span>
<span class="line"><span>自己裝環境、設定                AWS 負責底層</span></span>
<span class="line"><span>開著就計費（閒置也付費）        只在執行時付費</span></span>
<span class="line"><span>需要自己配置擴展               自動擴展</span></span></code></pre></div><p>AWS 的無伺服器代表有兩個：<strong>Lambda</strong>（無伺服器運算）與 <strong>Fargate</strong>（無伺服器容器，見下一章）。</p><h2 id="aws-lambda" tabindex="-1">AWS Lambda <a class="header-anchor" href="#aws-lambda" aria-label="Permalink to &quot;AWS Lambda&quot;">​</a></h2><p>Lambda 是 <strong>FaaS（Function as a Service，函式即服務）</strong>：你上傳一段程式（函式），由事件觸發後自動執行，全程不用管伺服器。</p><h3 id="它解決什麼問題" tabindex="-1">它解決什麼問題 <a class="header-anchor" href="#它解決什麼問題" aria-label="Permalink to &quot;它解決什麼問題&quot;">​</a></h3><p>用 EC2 時，你得讓一台伺服器<strong>一直開著等</strong>——即使它大部分時間閒著沒事做，你也照樣付錢，而且流量變大時擴展要你自己處理。對於那種「偶爾才發生一次」的工作（有人上傳檔案時處理一下、每晚跑一次排程、支撐一個時有時無的 API），養一台常開的機器既浪費又麻煩。</p><p>Lambda 把這件事整個翻轉：<strong>沒有要維護的伺服器、程式只在被觸發時才跑、擴展自動發生、你只為實際用到的運算付費。</strong></p><h3 id="運作方式" tabindex="-1">運作方式 <a class="header-anchor" href="#運作方式" aria-label="Permalink to &quot;運作方式&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>設定觸發事件 → 事件發生 → Lambda 自動執行函式 → 按「呼叫次數 × 執行時間」計費</span></span>
<span class="line"><span></span></span>
<span class="line"><span>常見觸發事件：</span></span>
<span class="line"><span>  S3 有新檔案上傳</span></span>
<span class="line"><span>  收到 API Gateway 請求</span></span>
<span class="line"><span>  排定時間（定時任務）</span></span>
<span class="line"><span>  DynamoDB 資料變更</span></span></code></pre></div><h3 id="你需要設定的三件事" tabindex="-1">你需要設定的三件事 <a class="header-anchor" href="#你需要設定的三件事" aria-label="Permalink to &quot;你需要設定的三件事&quot;">​</a></h3><p>你不用碰伺服器，但要決定三個參數：</p><table tabindex="0"><thead><tr><th>設定</th><th>說明</th></tr></thead><tbody><tr><td><strong>執行環境（Runtime）</strong></td><td>選語言：Python、Node.js、Java、Go 等</td></tr><tr><td><strong>記憶體</strong></td><td>128 MB 到 10 GB</td></tr><tr><td><strong>逾時（Timeout）</strong></td><td>這個函式最長能跑多久，<strong>上限 15 分鐘</strong></td></tr></tbody></table><h3 id="特性" tabindex="-1">特性 <a class="header-anchor" href="#特性" aria-label="Permalink to &quot;特性&quot;">​</a></h3><table tabindex="0"><thead><tr><th>特性</th><th>說明</th></tr></thead><tbody><tr><td><strong>自動擴展</strong></td><td>事件大量湧入時，自動並行執行多個函式副本來消化（帳號預設有並行上限，約 1,000，可申請調高）</td></tr><tr><td><strong>閒置不收費</strong></td><td>沒有事件就不執行、不計費</td></tr><tr><td><strong>高可用內建</strong></td><td>AWS 自動跨多個可用區運行，你不用自己做</td></tr><tr><td><strong>無狀態（Stateless）</strong></td><td>每次執行都是獨立的，<strong>不保留上一次的資料</strong>；要保存狀態得寫到外部，如 S3 或 DynamoDB</td></tr></tbody></table><h3 id="計費" tabindex="-1">計費 <a class="header-anchor" href="#計費" aria-label="Permalink to &quot;計費&quot;">​</a></h3><p>Lambda 按兩個東西收費：<strong>呼叫次數</strong> + <strong>執行時間</strong>（時間再乘上你配置的記憶體大小）。<strong>不執行就完全不收費</strong>——沒有「開著等」的閒置成本，這正是它和 EC2 最根本的差別。</p><h3 id="一個具體例子-自動產生縮圖" tabindex="-1">一個具體例子：自動產生縮圖 <a class="header-anchor" href="#一個具體例子-自動產生縮圖" aria-label="Permalink to &quot;一個具體例子：自動產生縮圖&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>使用者上傳照片到 S3</span></span>
<span class="line"><span>      ↓（S3 事件觸發）</span></span>
<span class="line"><span>   Lambda 執行：讀原圖 → 產生縮圖</span></span>
<span class="line"><span>      ↓</span></span>
<span class="line"><span>   縮圖存回 S3</span></span></code></pre></div><p>整條流程<strong>沒有一台常開的伺服器</strong>：平常沒人上傳就零成本，一有上傳才跑、跑完就結束。這就是事件驅動 + 無伺服器最典型的例子。</p><h3 id="限制" tabindex="-1">限制 <a class="header-anchor" href="#限制" aria-label="Permalink to &quot;限制&quot;">​</a></h3><blockquote><p><strong>單次執行最長 15 分鐘</strong>：需要長時間執行的工作（長跑的批次、常駐的服務）不適合 Lambda。</p></blockquote><blockquote><p><strong>冷啟動（Cold Start）</strong>：函式很久沒被呼叫後，第一次啟動會有短暫的準備延遲。對絕大多數工作無感，但對「要求穩定極低延遲」的場景要留意。</p></blockquote><h2 id="aws-step-functions" tabindex="-1">AWS Step Functions <a class="header-anchor" href="#aws-step-functions" aria-label="Permalink to &quot;AWS Step Functions&quot;">​</a></h2><p>Step Functions 是無伺服器的工作流程編排服務：將多個 Lambda 函式與 AWS 服務依<strong>順序、條件分支、平行</strong>串成一條視覺化流程（<strong>狀態機</strong>），並自動處理步驟順序、重試與錯誤處理。</p><p><strong>與單一 Lambda 的差別：</strong> Lambda 是「一個步驟」；Step Functions 是「把多個步驟編排成完整流程」，無需自行撰寫串接、判斷、重試的膠合程式碼。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[開始]</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>Lambda：驗證訂單</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>  判斷庫存？</span></span>
<span class="line"><span>   ├─（庫存足）→ Lambda：扣款 → Lambda：安排出貨 → [結束]</span></span>
<span class="line"><span>   └─（庫存不足）→ Lambda：通知缺貨 → [結束]</span></span></code></pre></div><ul><li>適合：多步驟業務流程——訂單處理、審批流程、機器學習資料管線</li><li>同樣是無伺服器：不管底層伺服器，按步驟狀態轉換次數計費</li></ul><h2 id="重點整理" tabindex="-1">重點整理 <a class="header-anchor" href="#重點整理" aria-label="Permalink to &quot;重點整理&quot;">​</a></h2><ul><li><strong>無伺服器（Serverless）</strong> = 不管伺服器、AWS 全包、只在執行時付費；閒置不收費</li><li><strong>Lambda</strong>（FaaS）：事件觸發、自動擴展、閒置不收費；單次最長 <strong>15 分鐘</strong>——長時間工作不適合，改用 EC2 / 容器</li><li><strong>Step Functions</strong> = 無伺服器工作流程編排，把多個 Lambda / 服務依順序、分支、重試串成視覺化流程；看到「協調 / 編排多步驟」就是它</li></ul><table tabindex="0"><thead><tr><th>情境需求</th><th>答案</th></tr></thead><tbody><tr><td>事件觸發、短小任務、閒置不收費</td><td>Lambda</td></tr><tr><td>執行時間需超過 15 分鐘</td><td>EC2 或容器（非 Lambda）</td></tr><tr><td>串接多個步驟 / 服務、需條件分支與重試</td><td>Step Functions</td></tr></tbody></table>`,37)])])}const g=s(r,[["render",o]]);export{b as __pageData,g as default};
